import{_ as a,c as e,o as l,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Управление навыками: Запрос доступных навыков | opencode-agent-skills","description":"Изучите использование инструмента get_available_skills. Быстро находите навыки с помощью поиска, пространств имён и фильтрации, освоите ключевые функции обнаружения и управления навыками.","frontmatter":{"title":"Управление навыками: Запрос доступных навыков | opencode-agent-skills","sidebarTitle":"Быстрый поиск навыков","subtitle":"Управление навыками: Запрос доступных навыков","description":"Изучите использование инструмента get_available_skills. Быстро находите навыки с помощью поиска, пространств имён и фильтрации, освоите ключевые функции обнаружения и управления навыками.","tags":["Управление навыками","Использование инструментов","Пространство имён"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"ru/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"ru/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),i={name:"ru/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function t(p,s,o,c,d,r){return l(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="запрос-и-перечисление-доступных-навыков" tabindex="-1">Запрос и перечисление доступных навыков <a class="header-anchor" href="#запрос-и-перечисление-доступных-навыков" aria-label="Permalink to &quot;Запрос и перечисление доступных навыков&quot;">​</a></h1><h2 id="что-вы-сможете-сделать-после-изучения" tabindex="-1">Что вы сможете сделать после изучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-изучения" aria-label="Permalink to &quot;Что вы сможете сделать после изучения&quot;">​</a></h2><ul><li>Использовать инструмент <code>get_available_skills</code> для перечисления всех доступных навыков</li><li>Фильтровать определённые навыки с помощью поисковых запросов</li><li>Точно находить навыки с помощью пространств имён (например, <code>project:skill-name</code>)</li><li>Определять источники навыков и список исполняемых скриптов</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Вы хотите использовать определённый навык, но не помните его точное название. Возможно, вы знаете, что это навык в проекте, но не знаете, в каком пути обнаружения он находится. Или вы просто хотите быстро просмотреть, какие навыки доступны в текущем проекте.</p><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><ul><li><strong>Изучение нового проекта</strong>: при присоединении к новому проекту быстро узнайте, какие навыки доступны</li><li><strong>Неопределённость названия навыка</strong>: вы помните только часть названия или описание навыка, нужно нечёткое сопоставление</li><li><strong>Конфликт имён в нескольких пространствах</strong>: в проектном и пользовательском уровнях есть навыки с одинаковыми названиями, нужно явно указать, какой использовать</li><li><strong>Поиск скриптов</strong>: вы хотите узнать, какие автоматизированные скрипты доступны в каталоге навыка</li></ul><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Инструмент <code>get_available_skills</code> помогает вам просматривать все навыки, доступные в текущей сессии. Плагин автоматически сканирует навыки из 6 путей обнаружения:</p><div class="info custom-block"><p class="custom-block-title">Приоритет обнаружения навыков</p><ol><li><code>.opencode/skills/</code> (проектный уровень OpenCode)</li><li><code>.claude/skills/</code> (проектный уровень Claude)</li><li><code>~/.config/opencode/skills/</code> (пользовательский уровень OpenCode)</li><li><code>~/.claude/skills/</code> (пользовательский уровень Claude)</li><li><code>~/.claude/plugins/cache/</code> (кэш плагинов)</li><li><code>~/.claude/plugins/marketplaces/</code> (установленные плагины)</li></ol></div><p>Навыки с одинаковыми названиями сохраняются только по приоритету, первая найденная версия сохраняется, последующие игнорируются.</p><p>Информация, возвращаемая инструментом, включает:</p><ul><li><strong>Название навыка</strong></li><li><strong>Метку источника</strong> (project, user, claude-project и т. д.)</li><li><strong>Описание</strong></li><li><strong>Список исполняемых скриптов</strong> (если есть)</li></ul><div class="tip custom-block"><p class="custom-block-title">Синтаксис пространства имён</p><p>Вы можете явно указать источник с помощью формата <code>namespace:skill-name</code>:</p><ul><li><code>project:my-skill</code> — использовать навык проектного уровня OpenCode (<code>.opencode/skills/</code>)</li><li><code>claude-project:my-skill</code> — использовать навык проектного уровня Claude (<code>.claude/skills/</code>)</li><li><code>user:my-skill</code> — использовать навык пользовательского уровня OpenCode (<code>~/.config/opencode/skills/</code>)</li><li><code>claude-user:my-skill</code> — использовать навык пользовательского уровня Claude (<code>~/.claude/skills/</code>)</li><li><code>claude-plugins:my-skill</code> — использовать навык из плагина Claude</li></ul></div><h2 id="пошаговое-руководство" tabindex="-1">Пошаговое руководство <a class="header-anchor" href="#пошаговое-руководство" aria-label="Permalink to &quot;Пошаговое руководство&quot;">​</a></h2><h3 id="шаг-1-перечисление-всех-доступных-навыков" tabindex="-1">Шаг 1: Перечисление всех доступных навыков <a class="header-anchor" href="#шаг-1-перечисление-всех-доступных-навыков" aria-label="Permalink to &quot;Шаг 1: Перечисление всех доступных навыков&quot;">​</a></h3><p>В OpenCode просто попросите ИИ перечислить навыки:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ввод пользователя:</span></span>
<span class="line"><span>Перечислите все доступные навыки</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ответ системы:</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Помощник по операциям Git и управлению ветками [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Инструмент для модульного тестирования и анализа покрытия</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Руководство по контейнеризации и развёртыванию Docker [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  Полный рабочий процесс разработки ПО</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: список навыков, каждый навык отображает название, метку источника, описание и список скриптов.</p><h3 id="шаг-2-использование-поисковых-запросов-для-фильтрации" tabindex="-1">Шаг 2: Использование поисковых запросов для фильтрации <a class="header-anchor" href="#шаг-2-использование-поисковых-запросов-для-фильтрации" aria-label="Permalink to &quot;Шаг 2: Использование поисковых запросов для фильтрации&quot;">​</a></h3><p>Если вы помните только часть названия навыка:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ввод пользователя:</span></span>
<span class="line"><span>Найдите навыки, содержащие &quot;docker&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ответ системы:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Руководство по контейнеризации и развёртыванию Docker [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Поиск сопоставляет ключевые слова в названиях и описаниях навыков, поддерживает подстановочный символ <code>*</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ввод пользователя:</span></span>
<span class="line"><span>Найдите навыки, начинающиеся с &quot;test&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ответ системы:</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Инструмент для модульного тестирования и анализа покрытия</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: отображаются только навыки, соответствующие условиям запроса.</p><h3 id="шаг-3-испытание-нечеткого-сопоставления-и-предложении" tabindex="-1">Шаг 3: Испытание нечёткого сопоставления и предложений <a class="header-anchor" href="#шаг-3-испытание-нечеткого-сопоставления-и-предложении" aria-label="Permalink to &quot;Шаг 3: Испытание нечёткого сопоставления и предложений&quot;">​</a></h3><p>Если вы ввели неправильное название навыка:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ввод пользователя:</span></span>
<span class="line"><span>Я хочу использовать docker-asistant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ответ системы:</span></span>
<span class="line"><span>No skills found matching &quot;docker-asistant&quot;. Did you mean &quot;docker-helper&quot;?</span></span></code></pre></div><p>Плагин на основе расстояния Левенштейна рассчитывает сходство и автоматически предлагает название наиболее близкого навыка.</p><p><strong>Что вы должны увидеть</strong>: сообщение об ошибке и правильное предложение навыка.</p><h3 id="шаг-4-точное-позиционирование-с-помощью-пространства-имен" tabindex="-1">Шаг 4: Точное позиционирование с помощью пространства имён <a class="header-anchor" href="#шаг-4-точное-позиционирование-с-помощью-пространства-имен" aria-label="Permalink to &quot;Шаг 4: Точное позиционирование с помощью пространства имён&quot;">​</a></h3><p>Предположим, что на проектном и пользовательском уровнях есть навык с названием <code>build-helper</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ввод пользователя:</span></span>
<span class="line"><span>Перечислите подробную информацию о build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ответ системы:</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  Конфигурация сборки, специфичная для проекта, и оптимизация компиляции [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>Если пользователь хочет навык пользовательского уровня:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ввод пользователя:</span></span>
<span class="line"><span>Используйте user:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ответ системы:</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  Универсальный инструментарий сборки и конфигурация непрерывной интеграции [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: с помощью префикса пространства имён можно получать доступ к навыкам с одинаковыми названиями из разных источников.</p><h3 id="шаг-5-проверка-исполняемых-скриптов" tabindex="-1">Шаг 5: Проверка исполняемых скриптов <a class="header-anchor" href="#шаг-5-проверка-исполняемых-скриптов" aria-label="Permalink to &quot;Шаг 5: Проверка исполняемых скриптов&quot;">​</a></h3><p>Просмотр скриптов в каталоге навыка:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ввод пользователя:</span></span>
<span class="line"><span>Какие скрипты есть у docker-helper?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ответ системы:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Руководство по контейнеризации и развёртыванию Docker [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Скрипты отображаются в квадратных скобках в информации о навыке, разделённые запятыми. Вы можете выполнить эти скрипты с помощью инструмента <code>run_skill_script</code>.</p><p><strong>Что вы должны увидеть</strong>: после названия навыка идёт список в формате <code>[scripts: путь_к_скрипту1, путь_к_скрипту2, ...]</code>.</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><ul><li>[ ] Можете ли вы перечислить все доступные навыки?</li><li>[ ] Можете ли вы фильтровать определённые навыки с помощью поисковых запросов?</li><li>[ ] Понимаете ли вы значение меток источников навыков (project, user, claude-project и т. д.)?</li><li>[ ] Можете ли вы объяснить роль и синтаксис пространств имён навыков?</li><li>[ ] Можете ли вы определить список исполняемых скриптов из информации о навыке?</li></ul><h2 id="предупреждения-о-подводных-камнях" tabindex="-1">Предупреждения о подводных камнях <a class="header-anchor" href="#предупреждения-о-подводных-камнях" aria-label="Permalink to &quot;Предупреждения о подводных камнях&quot;">​</a></h2><h3 id="ловушка-1-перекрытие-навыков-с-одинаковыми-названиями" tabindex="-1">Ловушка 1: Перекрытие навыков с одинаковыми названиями <a class="header-anchor" href="#ловушка-1-перекрытие-навыков-с-одинаковыми-названиями" aria-label="Permalink to &quot;Ловушка 1: Перекрытие навыков с одинаковыми названиями&quot;">​</a></h3><p>Если на проектном и пользовательском уровнях есть навыки с одинаковыми названиями, вы можете быть озадачены тем, почему загружается не тот навык, который вы ожидаете.</p><p><strong>Причина</strong>: навыки обнаруживаются по приоритету, проектный уровень имеет приоритет над пользовательским, для одинаковых названий сохраняется только первый.</p><p><strong>Решение</strong>: явно укажите пространство имён, например, <code>user:my-skill</code>, а не просто <code>my-skill</code>.</p><h3 id="ловушка-2-чувствительность-к-регистру-в-поиске" tabindex="-1">Ловушка 2: Чувствительность к регистру в поиске <a class="header-anchor" href="#ловушка-2-чувствительность-к-регистру-в-поиске" aria-label="Permalink to &quot;Ловушка 2: Чувствительность к регистру в поиске&quot;">​</a></h3><p>Поисковые запросы используют регулярные выражения, но установлен флаг <code>i</code>, поэтому поиск не чувствителен к регистру.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Эти поиски эквивалентны</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="ловушка-3-экранирование-подстановочных-символов" tabindex="-1">Ловушка 3: Экранирование подстановочных символов <a class="header-anchor" href="#ловушка-3-экранирование-подстановочных-символов" aria-label="Permalink to &quot;Ловушка 3: Экранирование подстановочных символов&quot;">​</a></h3><p>В поиске <code>*</code> автоматически преобразуется в регулярное выражение <code>.*</code>, ручное экранирование не требуется:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Поиск навыков, начинающихся с &quot;test&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Эквивалентно регулярному выражению /test.*/i</span></span></code></pre></div><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><p><code>get_available_skills</code> — это инструмент для изучения экосистемы навыков, поддерживающий:</p><ul><li><strong>Перечисление всех навыков</strong>: вызов без параметров</li><li><strong>Поиск и фильтрацию</strong>: сопоставление названий и описаний с помощью параметра <code>query</code></li><li><strong>Пространства имён</strong>: точное позиционирование с помощью <code>namespace:skill-name</code></li><li><strong>Предложения по нечёткому сопоставлению</strong>: автоматическое подсказывание правильного названия при орфографических ошибках</li><li><strong>Список скриптов</strong>: отображение исполняемых автоматизированных скриптов</li></ul><p>Плагин автоматически внедряет список навыков при начале сессии, поэтому обычно вам не нужно вызывать этот инструмент вручную. Однако он полезен в следующих сценариях:</p><ul><li>Хотите быстро просмотреть доступные навыки</li><li>Не помните точное название навыка</li><li>Нужно различать одинаковые названия навыков из разных источников</li><li>Хотите просмотреть список скриптов определённого навыка</li></ul><h2 id="предварительныи-обзор-следующего-урока" tabindex="-1">Предварительный обзор следующего урока <a class="header-anchor" href="#предварительныи-обзор-следующего-урока" aria-label="Permalink to &quot;Предварительный обзор следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../loading-skills-into-context/">Загрузка навыков в контекст сессии</a></strong>.</p><p>Вы узнаете:</p><ul><li>Использование инструмента use_skill для загрузки навыков в текущую сессию</li><li>Понимание того, как содержимое навыков внедряется в контекст в формате XML</li><li>Освоение механизма Synthetic Message Injection (внедрение синтетических сообщений)</li><li>Узнайте, как навыки остаются доступными после сжатия сессии</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы просмотреть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Определение инструмента GetAvailableSkills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>Функция discoverAllSkills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>Функция resolveSkill</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>Функция findClosestMatch</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>Ключевые типы</strong>:</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>: перечисление меток источников навыков</li></ul><p><strong>Ключевые константы</strong>:</p><ul><li>Порог нечёткого сопоставления: <code>0.4</code> (<code>utils.ts:124</code>) — если сходство ниже этого значения, предложения не возвращаются</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>GetAvailableSkills()</code>: возвращает форматированный список навыков, поддерживает фильтрацию по запросам и предложения по нечёткому сопоставлению</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>: поддерживает разбор навыков в формате <code>namespace:skill-name</code></li><li><code>findClosestMatch(input: string, candidates: string[])</code>: на основе нескольких стратегий сопоставления (префикс, включение, расстояние редактирования) рассчитывает лучшее совпадение</li></ul><p><strong>Бизнес-правила</strong>:</p><ul><li>Навыки с одинаковыми названиями дедуплицируются по порядку обнаружения, сохраняется только первый (<code>skills.ts:258</code>)</li><li>Поисковые запросы поддерживают подстановочный символ <code>*</code>, который автоматически преобразуется в регулярное выражение (<code>tools.ts:43</code>)</li><li>Предложения по нечёткому сопоставлению срабатывают только при наличии параметра запроса и отсутствии результатов (<code>tools.ts:49-57</code>)</li></ul></details>`,64)])])}const k=a(i,[["render",t]]);export{u as __pageData,k as default};
